@app.route("/")
@app.route("/index.html")
def index():
    return Response(HTML_BYTES, mimetype="text/html; charset=utf-8")

@app.route("/favicon.ico")
def favicon():
    return "", 204

@app.route("/api/generar", methods=["POST"])
def generar_video():
    try:
        job_id  = str(uuid.uuid4())[:8]
        job_dir = os.path.join(JOBS_FOLDER, job_id)
        imgs_dir = os.path.join(job_dir, "imagenes")
        os.makedirs(imgs_dir, exist_ok=True)

        audio = request.files.get("audio")
        if not audio or audio.filename == '':
            return jsonify({"error": "Falta el archivo de audio"}), 400
        audio_path = os.path.join(job_dir, "audio.mp3")
        audio.save(audio_path)

        guion = request.form.get("guion", "").strip()
        if not guion:
            return jsonify({"error": "El guión está vacío"}), 400
        guion_path = os.path.join(job_dir, "guion.txt")
        with open(guion_path, "w", encoding="utf-8") as f:
            f.write(guion)

        imagen_keys = sorted(
            [k for k in request.files.keys() if k.startswith("imagen_")],
            key=lambda x: int(x.split("_")[1])
        )
        if not imagen_keys:
            return jsonify({"error": "No se subieron imágenes"}), 400

        for i, key in enumerate(imagen_keys):
            img_file = request.files[key]
            ct  = img_file.content_type or "image/png"
            ext = {"image/jpeg":".jpg","image/jpg":".jpg",
                   "image/png":".png","image/webp":".webp"}.get(ct, ".jpg")
            img_file.save(os.path.join(imgs_dir, f"img_{i:03d}{ext}"))

        resolucion = request.form.get("resolucion", "1920x1080")
        fade       = float(request.form.get("fade", "0"))
        modelo     = request.form.get("modelo", "base")
        transicion = request.form.get("transicion", "none")
        movimiento = request.form.get("movimiento", "none")
        trans_dur  = float(request.form.get("trans_dur", "0.8"))
        shake      = request.form.get("shake", "false")

        jobs[job_id] = {
            "id": job_id, "estado": "procesando", "progreso": 0,
            "mensaje": "Iniciando...", "logs": [], "video_url": None,
            "inicio": time.time()
        }

        threading.Thread(
            target=procesar_video,
            args=(job_id, job_dir, audio_path, guion_path, imgs_dir,
                  resolucion, fade, modelo, transicion, movimiento, trans_dur, shake),
            daemon=True
        ).start()

        return jsonify({"job_id": job_id})

    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({"error": str(e)}), 500

@app.route("/api/estado/<job_id>")
def estado_job(job_id):
    if job_id not in jobs:
        return jsonify({"error": "Job no encontrado"}), 404
    return jsonify(jobs[job_id])

@app.route("/api/descargar/<job_id>")
def descargar_video(job_id):
    path = os.path.join(JOBS_FOLDER, job_id, "video_final.mp4")
    if not os.path.exists(path):
        return jsonify({"error": "Video no encontrado"}), 404
    return send_file(path, as_attachment=True,
                     download_name=f"video_{job_id}.mp4")

# ══════════════════════════════════════════════════════════════════
# WHISPER MATCHING
# ══════════════════════════════════════════════════════════════════

def limpiar(texto):
    texto = texto.lower().strip()
    texto = re.sub(r'[¿¡.,;:!?\-–—"""\'()\[\]]', '', texto)
    texto = re.sub(r'\s+', ' ', texto)
    return texto

def contar_palabras_comunes(a, b):
    pa = set(limpiar(a).split())
    pb = set(limpiar(b).split())
    if not pa: return 0
    return len(pa & pb) / len(pa)

def asignar_timestamps(escenas, segmentos, duracion_total):
    n = len(escenas)
    if not segmentos:
        return _proporcional(escenas, duracion_total)

    asignaciones = []
    ultimo = 0
    for i, escena in enumerate(escenas):
        mejor_score, mejor_idx = -1, ultimo
        limite = min(len(segmentos), ultimo + max(5, len(segmentos) // n * 3))
        for j in range(ultimo, limite):
            st = segmentos[j].get("text", "")
            score = contar_palabras_comunes(escena, st)
            if j + 1 < len(segmentos):
                t2 = st + " " + segmentos[j+1].get("text","")
                score = max(score, contar_palabras_comunes(escena, t2) * 0.9)
            if score > mejor_score:
                mejor_score, mejor_idx = score, j
        asignaciones.append((mejor_idx, mejor_score))
        ultimo = mejor_idx

    resultado = []
    for i, (idx, score) in enumerate(asignaciones):
        seg   = segmentos[idx]
        inicio = _refinar_inicio(escenas[i], seg)
        if i < n - 1:
            seg_sig = segmentos[asignaciones[i+1][0]]
            fin = _refinar_inicio(escenas[i+1], seg_sig)
            if fin <= inicio: fin = seg["end"]
        else:
            fin = duracion_total
        dur = max(0.5, round(fin - inicio, 3))
        resultado.append({"inicio": round(inicio,3), "fin": round(inicio+dur,3),
                           "duracion": dur, "seg_idx": idx, "score": round(score,3)})
    return resultado

def _refinar_inicio(escena, seg):
    words = seg.get("words", [])
    if not words: return seg["start"]
    TRIVIALES = {"el","la","los","las","un","una","de","en","a","y","o","que",
                 "se","es","su","me","te","con","por","para","si","no","ya"}
    claves = [w for w in limpiar(escena).split() if w not in TRIVIALES and len(w)>2]
    primera = (claves or limpiar(escena).split()[:1] or [None])[0]
    if not primera: return seg["start"]
    for w in words:
        if limpiar(w.get("word","")) == primera:
            return float(w.get("start", seg["start"]))
    return seg["start"]

def _proporcional(escenas, duracion_total):
    dur = duracion_total / len(escenas)
    return [{"inicio":round(i*dur,3),"fin":round((i+1)*dur,3),
             "duracion":round(dur,3),"seg_idx":i,"score":0}
            for i in range(len(escenas))]

# ══════════════════════════════════════════════════════════════════
# PROCESAMIENTO PRINCIPAL
# ══════════════════════════════════════════════════════════════════

MODAL_URL = "https://davidestebanbermudez14--motor-video-cpa-renderizar.modal.run"

def procesar_video(job_id, job_dir, audio_path, guion_path, imgs_dir,
                   resolucion, fade, modelo, transicion, movimiento, trans_dur, shake):

    def log(msg, progreso=None):
        jobs[job_id]["logs"].append(msg)
        jobs[job_id]["mensaje"] = msg
        if progreso is not None:
            jobs[job_id]["progreso"] = progreso
        print(f"[{job_id}] {msg}")

    try:
        import whisper

        log("📄 Leyendo guión...", 5)
        with open(guion_path, "r", encoding="utf-8") as f:
            escenas = [e.strip() for e in f.read().split("\n") if e.strip()]
        log(f"✓ {len(escenas)} escenas", 10)

        log("🖼️ Cargando imágenes...", 12)
        exts = ('.jpg','.jpeg','.png','.webp')
        imagenes = sorted(
            [str(p) for p in __import__("pathlib").Path(imgs_dir).iterdir() if p.suffix.lower() in exts],
            key=lambda p: os.path.basename(p)
        )
        if not imagenes:
            raise Exception("No se encontraron imágenes")
        log(f"✓ {len(imagenes)} imágenes | {len(escenas)} escenas", 15)

        log("⏱️ Analizando audio...", 18)
        result = subprocess.run(
            ["ffprobe","-v","error","-show_entries","format=duration",
             "-of","json", audio_path],
            capture_output=True, text=True
        )
        if result.returncode != 0:
            raise Exception(f"ffprobe: {result.stderr}")
        try:
            _parsed = json.loads(result.stdout)
            _dur = (_parsed.get("format") or {}).get("duration")
            if _dur is None:
                _res2 = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "stream=duration","-of","json",audio_path],capture_output=True,text=True)
                _streams = json.loads(_res2.stdout).get("streams",[])
                _dur = next((s["duration"] for s in _streams if s.get("duration")),None)
            duracion_total = float(_dur)
        except Exception as _de:
            raise Exception(f"No se pudo leer la duración del audio: {_de}")
        log(f"✓ Audio: {duracion_total:.1f}s", 20)

        log(f"🎤 Transcribiendo con Whisper ({modelo})...", 22)
        wmodel = whisper.load_model(modelo)
        resultado = wmodel.transcribe(audio_path, language="es", word_timestamps=True)
        segmentos = resultado.get("segments", [])
        log(f"✓ {len(segmentos)} segmentos transcritos", 30)

        log("🔍 Asignando timestamps...", 32)
        timestamps = asignar_timestamps(escenas, segmentos, duracion_total)
        log(f"✓ {len(timestamps)} timestamps listos", 35)

        log("🚀 Codificando archivos para Modal...", 40)
        with open(audio_path, "rb") as f:
            audio_b64 = base64.b64encode(f.read()).decode("utf-8")

        extra = trans_dur if transicion != "none" else 0.0
        escenas_modal = []
        for i, ts in enumerate(timestamps):
            idx_img = min(i, len(imagenes)-1)
            with open(imagenes[idx_img], "rb") as f:
                img_b64 = base64.b64encode(f.read()).decode("utf-8")
            escenas_modal.append({
                "imagen_b64": img_b64,
                "duracion": ts["duracion"] + (extra if i < len(timestamps)-1 else 0.0),
                "movimiento": movimiento
            })

        payload = {
            "audio_b64":  audio_b64,
            "escenas":    escenas_modal,
            "resolucion": resolucion.replace("x",":"),
            "transicion": transicion,
            "trans_dur":  trans_dur,
            "fade":       fade,
            "shake":      shake
        }

        log(f"⚡ Procesando en la nube ({len(escenas)} escenas)...", 60)
        respuesta = requests.post(MODAL_URL, json=payload, timeout=900)
        respuesta.raise_for_status()
        datos = respuesta.json()

        if not datos.get("success"):
            raise Exception(datos.get("error", "Error en Modal"))

        log("📥 Descargando video final...", 90)
        video_final = os.path.join(job_dir, "video_final.mp4")
        with open(video_final, "wb") as f:
            f.write(base64.b64decode(datos["video_b64"]))

        size_mb = os.path.getsize(video_final) / (1024*1024)
        log(f"✅ Video listo — {size_mb:.1f} MB", 100)
        jobs[job_id].update({
            "estado": "completado",
            "video_url": f"/api/descargar/{job_id}",
            "size_mb":   round(size_mb, 1),
            "duracion":  round(duracion_total, 1),
            "escenas":   len(escenas)
        })

    except Exception as e:
        import traceback; traceback.print_exc()
        log(f"❌ Error: {str(e)}")
        jobs[job_id].update({"estado": "error", "error": str(e)})


