@app.route("/api/voz/generar", methods=["POST"])
def voz_generar():
    """
    Sends text to n8n in safe chunks.
    Sanitizes text so n8n's JSON expression {{ $json.data }} never breaks.
    """
    import re as _re, time as _t
    from pathlib import Path as _P

    data     = request.get_json() or {}
    pn       = data.pop("project_name", "")
    voice_id = data.get("voice_id", "")
    text     = data.get("data", "").strip()

    N8N_URL   = "https://n8n-n8n.y9c1cn.easypanel.host/webhook/541b2f00-1fbb-443f-8225-25dd5969da01"
    MAX_CHARS = 900

    def _sanitize(t):
        """Remove chars that break n8n JSON expressions."""
        t = t.replace("\r\n", " ").replace("\n", " ").replace("\r", " ")
        t = t.replace('"', "'").replace("\\", " ")
        t = " ".join(t.split())   # collapse multiple spaces
        return t.strip()

    def _split(txt, max_c):
        """Split at sentence boundaries, max max_c chars each."""
        chunks, start = [], 0
        while start < len(txt):
            end_pos = start + max_c
            if end_pos >= len(txt):
                chunk = txt[start:].strip()
                if chunk: chunks.append(chunk)
                break
            cut = -1
            for i in range(end_pos, start + max_c // 2, -1):
                if txt[i] in ".!?": cut = i + 1; break
            if cut == -1:
                for i in range(end_pos, start + max_c // 2, -1):
                    if txt[i] == " ": cut = i; break
            if cut == -1: cut = end_pos
            chunk = txt[start:cut].strip()
            if chunk: chunks.append(chunk)
            start = cut
        return chunks

    clean  = _sanitize(text)
    chunks = _split(clean, MAX_CHARS) if len(clean) > MAX_CHARS else [clean]

    all_fragments = []
    for chunk in chunks:
        try:
            r = requests.post(
                N8N_URL,
                json={"data": chunk, "voice_id": voice_id},
                timeout=300
            )
            result = r.json()
            _res   = result[0] if isinstance(result, list) else result
            if isinstance(_res, dict) and _res.get("fragments"):
                for _frag in _res["fragments"]: _frag["chunkText"] = chunk; all_fragments.append(_frag)
            else:
                err = _res.get("message", str(_res)[:120]) if isinstance(_res, dict) else str(_res)[:120]
                return jsonify({"error": f"n8n error: {err}"}), 500
        except Exception as e:
            return jsonify({"error": str(e)}), 500

    if not all_fragments:
        return jsonify({"error": "No se generaron fragmentos"}), 500

    return jsonify({"fragments": all_fragments})


