# ── Proyecto contenido (imágenes + videos con matching) ──────────────────
@app.route("/api/proyectos/contenido")
def proyecto_contenido():
    """Returns matched images/videos for a project"""
    proj_name = request.args.get("project", "")
    if not proj_name:
        return jsonify({"error": "No project"}), 400
    from pathlib import Path as _P
    proj_dir = _P(JOBS_FOLDER) / proj_name
    img_dir  = proj_dir / "imagen"
    vid_dir  = proj_dir / "video"

    img_exts = {'.jpg', '.jpeg', '.png', '.webp', '.gif', '.bmp', '.JPG', '.PNG', '.JPEG', '.WEBP'}
    images   = []
    if img_dir.exists():
        for f in img_dir.iterdir():
            if f.is_file() and f.suffix.lower().lstrip('.') in {'jpg','jpeg','png','webp','gif','bmp'}:
                images.append(f)
        images.sort(key=lambda f: f.name)
    videos   = sorted([f for f in vid_dir.glob("*.mp4")],
                      key=lambda f: f.name) if vid_dir.exists() else []

    # Sort by creation time (oldest first)
    def _ctime(p):
        st = p.stat()
        return getattr(st, "st_birthtime", None) or st.st_mtime
    images.sort(key=_ctime)
    videos.sort(key=_ctime)

    # Index videos by exact stem (001_foto1.mp4 → key "001_foto1")
    vid_by_stem = {v.stem: v.name for v in videos}

    # Build scenes: each image → match video by EXACT stem (same name, different ext)
    seen_stems = set()
    scenes = []
    for img in images:
        seen_stems.add(img.stem)
        vid = vid_by_stem.get(img.stem)   # 001_foto1.jpg ↔ 001_foto1.mp4
        scenes.append({
            "index":     img.stem,        # full stem as index for display
            "image":     img.name,
            "video":     vid,
            "has_video": vid is not None
        })

    # Add orphan videos (no matching image)
    for v in videos:
        if v.stem not in seen_stems:
            seen_stems.add(v.stem)
            scenes.append({
                "index":     v.stem,
                "image":     None,
                "video":     v.name,
                "has_video": True
            })

    # Sort by IMAGE creation time (primary key).
    # Videos inherit their image's ctime for ordering — ensures videos corresponding
    # to the first images always appear first, regardless of video creation time.
    def _scene_order(s):
        if s["image"] and (img_dir / s["image"]).exists():
            return _ctime(img_dir / s["image"])
        elif s["video"] and (vid_dir / s["video"]).exists():
            return _ctime(vid_dir / s["video"])
        return 0
    scenes.sort(key=_scene_order)

    return jsonify({
        "scenes":      scenes,
        "total":       len(scenes),
        "with_video":  sum(1 for s in scenes if s["has_video"]),
        "images_only": sum(1 for s in scenes if not s["has_video"]),
        "debug": {
            "img_dir":    str(img_dir),
            "img_count":  len(images),
            "vid_count":  len(videos),
            "img_dir_exists": img_dir.exists(),
        }
    })


# ── Smart Render ─────────────────────────────────────────────────────────
@app.route("/api/render_inteligente", methods=["POST"])
def render_inteligente():
    """Local FFmpeg render using project videos+images+audio"""
    try:
        proj_name  = request.form.get("project_name", "")
        render_mode = request.form.get("render_mode", "smart")  # images|videos|smart
        guion      = request.form.get("guion", "").strip()
        resolucion = request.form.get("resolucion", "1920x1080")
        modelo     = request.form.get("modelo", "base")
        transicion = request.form.get("transicion", "none")
        trans_dur  = float(request.form.get("trans_dur", "0.8"))
        movimiento = request.form.get("movimiento", "none")
        shake      = request.form.get("shake", "false") == "true"
        
        if not proj_name:
            return jsonify({"error": "Proyecto requerido"}), 400
        
        from pathlib import Path as _P
        proj_dir = _P(JOBS_FOLDER) / proj_name
        img_dir  = proj_dir / "imagen"
        vid_dir  = proj_dir / "video"
        audio_dir = proj_dir / "audio"
        out_dir   = proj_dir / "video_final"
        out_dir.mkdir(parents=True, exist_ok=True)
        
        # Get audio
        audio = request.files.get("audio")
        if audio and audio.filename:
            audio_path = str(audio_dir / "render_audio.mp3")
            audio_dir.mkdir(parents=True, exist_ok=True)
            audio.save(audio_path)
        else:
            # Try to find existing audio in project
            audios = list(audio_dir.glob("*")) if audio_dir.exists() else []
            audio_path = str(audios[0]) if audios else None
        
        if not audio_path or not os.path.exists(audio_path):
            return jsonify({"error": "No se encontró audio"}), 400
        
        # Get images — sorted by creation time (same order as original upload)
        def _ctime_r(p):
            st = p.stat(); return getattr(st,"st_birthtime",None) or st.st_mtime
        images = []
        if img_dir.exists():
            for _f in img_dir.iterdir():
                if _f.is_file() and _f.suffix.lower().lstrip('.') in {'jpg','jpeg','png','webp','gif','bmp'}:
                    images.append(_f)
            images.sort(key=_ctime_r)   # oldest first
        if not images:
            return jsonify({"error": "No hay imágenes en el proyecto"}), 400

        videos = sorted([f for f in vid_dir.glob("*.mp4")], key=_ctime_r) if vid_dir.exists() else []

        # Index videos by exact stem: foto1.mp4 → {"foto1": Path(...)}
        vid_index = {v.stem: v for v in videos}
        
        # Save guion if provided
        if guion:
            guion_path = str(proj_dir / "guion" / "guion_render.txt")
            os.makedirs(os.path.dirname(guion_path), exist_ok=True)
            open(guion_path,"w",encoding="utf-8").write(guion)
        
        job_id = str(uuid.uuid4())[:8]
        jobs[job_id] = {"id":job_id,"estado":"procesando","progreso":0,"mensaje":"Iniciando...","logs":[],"video_url":None,"inicio":time.time()}
        
        threading.Thread(
            target=procesar_render_inteligente,
            args=(job_id, images, vid_index, audio_path, guion, resolucion, modelo,
                  transicion, trans_dur, movimiento, shake, render_mode, str(out_dir)),
            daemon=True
        ).start()
        
        return jsonify({"job_id": job_id})
    except Exception as e:
        import traceback; traceback.print_exc()
        return jsonify({"error": str(e)}), 500


def procesar_render_inteligente(job_id, images, vid_index, audio_path, guion,
                                 resolucion, modelo, transicion, trans_dur,
                                 movimiento, shake, render_mode, out_dir):
    """Modal GPU render — parallel batches for maximum GPU throughput."""
    import tempfile as _tmp, shutil as _sh, gzip as _gz, math as _math
    from concurrent.futures import ThreadPoolExecutor as _TPE
    import io as _io

    _MODAL_URL = "https://davidestebanbermudez14--motor-video-cpa-renderizar.modal.run"
    BATCH_SIZE = 20   # scenes per Modal call — tune to balance cold-start vs payload size

    def log(msg, pct=None):
        jobs[job_id]["logs"].append(msg)
        jobs[job_id]["mensaje"] = msg
        if pct is not None: jobs[job_id]["progreso"] = pct
        print(f"[{job_id}] {msg}")

    tmp_dir = _tmp.mkdtemp()
    try:
        # ── Audio duration ────────────────────────────────────────────────────
        log("⏱️ Analizando audio...", 3)
        _res = subprocess.run(["ffprobe","-v","error","-show_entries","format=duration",
                               "-of","json",audio_path], capture_output=True, text=True)
        try:
            _parsed = json.loads(_res.stdout)
            _dur = (_parsed.get("format") or {}).get("duration")
            if _dur is None:
                _r2 = subprocess.run(["ffprobe","-v","error","-show_entries",
                    "stream=duration","-of","json",audio_path],capture_output=True,text=True)
                _dur = next((s["duration"] for s in json.loads(_r2.stdout).get("streams",[])
                             if s.get("duration")), None)
            duracion_total = float(_dur)
        except Exception as _de:
            raise Exception(f"No se pudo leer la duración del audio: {_de}")
        log(f"✓ Audio: {duracion_total:.1f}s", 7)

        # ── Whisper timestamps ────────────────────────────────────────────────
        escenas_texto = [e.strip() for e in guion.split("\n") if e.strip()] if guion else []
        if not escenas_texto:
            escenas_texto = [f"Escena {i+1}" for i in range(len(images))]
        if guion and guion.strip():
            log(f"🎤 Transcribiendo con Whisper ({modelo})...", 10)
            import whisper as _whisper
            wm = _whisper.load_model(modelo)
            resultado = wm.transcribe(audio_path, language="es", word_timestamps=True)
            segmentos = resultado.get("segments", [])
            log(f"✓ {len(segmentos)} segmentos", 20)
            timestamps = asignar_timestamps(escenas_texto, segmentos, duracion_total)
        else:
            dur_eq = duracion_total / max(1, len(escenas_texto))
            timestamps = [{"inicio": i*dur_eq, "fin": (i+1)*dur_eq, "duracion": dur_eq}
                          for i in range(len(escenas_texto))]
        log(f"✓ {len(timestamps)} timestamps", 22)

        # ── Build scene list ──────────────────────────────────────────────────
        scenes = []
        for i, img in enumerate(images):
            ts      = timestamps[i] if i < len(timestamps) else timestamps[-1]
            vid     = vid_index.get(img.stem) if render_mode in ("smart","videos") else None
            vid_path = str(vid) if vid and os.path.exists(str(vid)) else None
            scenes.append({"type": "video" if vid_path else "image",
                           "img_path": str(img), "vid_path": vid_path,
                           "duracion": max(0.5, ts["duracion"])})
        n_vid = sum(1 for s in scenes if s["type"]=="video")
        log(f"📋 {len(scenes)} escenas — {n_vid} video · {len(scenes)-n_vid} imagen", 25)

        # ── Encode each scene locally (parallel, 16 workers) ─────────────────
        # Images → JPEG 960px (Modal GPU upscales); Videos → 480p ultrafast trim
        log("🖥️ Codificando escenas localmente...", 28)
        try:
            w_res, h_res = [int(x) for x in resolucion.split("x")]
        except:
            w_res, h_res = 1920, 1080

        def _encode(args):
            i, sc = args
            dur = sc["duracion"]
            if sc["type"] == "video":
                clip_out = os.path.join(tmp_dir, f"v{i:04d}.mp4")
                subprocess.run(["ffmpeg","-y","-i",sc["vid_path"],"-t",str(dur),
                                "-vf","scale=-2:min(480\\,ih):flags=lanczos",
                                "-c:v","libx264","-preset","ultrafast","-crf","28",
                                "-an","-r","24","-pix_fmt","yuv420p",
                                "-movflags","+faststart", clip_out],
                               capture_output=True)
                if os.path.exists(clip_out) and os.path.getsize(clip_out) > 500:
                    frm = os.path.join(tmp_dir, f"f{i:04d}.jpg")
                    subprocess.run(["ffmpeg","-y","-i",clip_out,"-frames:v","1",
                                    "-vf","scale=960:-2","-q:v","4",frm],
                                   capture_output=True)
                    with open(clip_out,"rb") as f: vb = base64.b64encode(f.read()).decode()
                    src = frm if os.path.exists(frm) else sc["img_path"]
                    with open(src,"rb") as f: ib = base64.b64encode(f.read()).decode()
                    return {"imagen_b64":ib,"video_b64":vb,"duracion":dur,
                            "movimiento":movimiento,"is_video":True}
            # Image
            try:
                from PIL import Image as _Im
                with _Im.open(sc["img_path"]) as im:
                    if im.mode != "RGB": im = im.convert("RGB")
                    ms = 960
                    if max(im.width,im.height) > ms:
                        r = ms/max(im.width,im.height)
                        im = im.resize((int(im.width*r),int(im.height*r)),_Im.BILINEAR)
                    buf = _io.BytesIO()
                    im.save(buf,format="JPEG",quality=78,optimize=True)
                    ib = base64.b64encode(buf.getvalue()).decode()
            except Exception:
                with open(sc["img_path"],"rb") as f: ib = base64.b64encode(f.read()).decode()
            return {"imagen_b64":ib,"duracion":dur,"movimiento":movimiento,"is_video":False}

        with _TPE(max_workers=min(len(scenes),16)) as ex:
            escenas_modal = list(ex.map(_encode, enumerate(scenes)))
        log(f"✓ {len(escenas_modal)} escenas codificadas", 40)

        # Add transition overlap duration
        extra = trans_dur if transicion != "none" else 0.0
        for i,sc in enumerate(escenas_modal):
            if i < len(escenas_modal)-1:
                sc["duracion"] = round(sc["duracion"]+extra, 3)

        # ── Compress audio: 64k mono for faster upload ────────────────────────
        _asm = os.path.join(tmp_dir,"audio_s.mp3")
        _ra = subprocess.run(["ffmpeg","-y","-i",audio_path,"-ar","44100","-ac","1",
                               "-b:a","64k","-movflags","+faststart",_asm],
                              capture_output=True)
        audio_b64 = base64.b64encode(
            open(_asm if _ra.returncode==0 and os.path.exists(_asm) and
                 os.path.getsize(_asm)>1000 else audio_path,"rb").read()).decode()

        # ── Split into batches and call Modal in PARALLEL ─────────────────────
        n_batches = max(1, _math.ceil(len(escenas_modal) / BATCH_SIZE))
        batches   = [escenas_modal[i*BATCH_SIZE:(i+1)*BATCH_SIZE]
                     for i in range(n_batches)]
        log(f"⚡ Enviando {n_batches} batch(es) a Modal en paralelo...", 50)

        # Each batch: send only its scenes + the audio
        # Modal returns video_b64 clip per batch → we stitch locally
        batch_clips = [None] * n_batches

        # Generate a silent audio clip matching total duration for batches that need it
        # Modal requires a valid audio_b64 — use silent mono mp3
        _silent = os.path.join(tmp_dir,"silent.mp3")
        subprocess.run(["ffmpeg","-y","-f","lavfi","-i","anullsrc=r=44100:cl=mono",
                        "-t",str(duracion_total),"-b:a","32k",_silent],
                       capture_output=True)
        _silent_b64 = base64.b64encode(
            open(_silent,"rb").read() if os.path.exists(_silent) else b"").decode()

        def _call_modal(args):
            b_idx, batch_scenes = args
            payload = {
                "audio_b64":  _silent_b64,  # silent audio — we mix real audio after stitching
                "escenas":    batch_scenes,
                "resolucion": resolucion.replace("x",":"),
                "transicion": transicion,
                "trans_dur":  trans_dur,
                "fade":       0,
                "shake":      "false",  # no shake per batch — apply globally if needed
            }
            r = requests.post(_MODAL_URL, json=payload, timeout=900)
            r.raise_for_status()
            d = r.json()
            if not d.get("success"):
                raise Exception(f"Modal batch {b_idx}: {d.get('error','error')}")
            return b_idx, d["video_b64"]

        if n_batches == 1:
            # Single batch — send with audio, let Modal do full mix
            payload = {
                "audio_b64":  audio_b64,
                "escenas":    escenas_modal,
                "resolucion": resolucion.replace("x",":"),
                "transicion": transicion,
                "trans_dur":  trans_dur,
                "fade":       0,
                "shake":      "true" if shake else "false",
            }
            log("⚡ Enviando a Modal (1 batch)...", 55)
            resp = requests.post(_MODAL_URL, json=payload, timeout=900)
            resp.raise_for_status()
            datos = resp.json()
            if not datos.get("success"):
                raise Exception(datos.get("error","Error en Modal"))
            log("📥 Descargando...", 90)
            video_final = os.path.join(out_dir, f"render_{job_id}.mp4")
            with open(video_final,"wb") as f:
                f.write(base64.b64decode(datos["video_b64"]))
        else:
            # Multiple batches — parallel Modal calls, then stitch + add audio locally
            with _TPE(max_workers=n_batches) as ex:
                futs = list(ex.map(_call_modal, enumerate(batches)))
            futs.sort(key=lambda x: x[0])

            log("🔗 Uniendo batches...", 82)
            # Save each batch video
            batch_paths = []
            for b_idx, vb64 in futs:
                bp = os.path.join(tmp_dir, f"batch_{b_idx:03d}.mp4")
                with open(bp,"wb") as f: f.write(base64.b64decode(vb64))
                batch_paths.append(bp)

            # Concat batch clips
            concat_list = os.path.join(tmp_dir,"concat.txt")
            with open(concat_list,"w") as f:
                for bp in batch_paths: f.write(f"file '{bp}'\n")
            concat_out = os.path.join(tmp_dir,"concat.mp4")
            subprocess.run(["ffmpeg","-y","-f","concat","-safe","0","-i",concat_list,
                            "-c","copy",concat_out], capture_output=True)

            # Mix audio
            log("🎵 Mezclando audio...", 90)
            video_final = os.path.join(out_dir, f"render_{job_id}.mp4")
            fade_args = ["-af",f"afade=t=out:st={max(0,duracion_total-1.5)}:d=1.5"]                         if duracion_total > 3 else []
            subprocess.run(["ffmpeg","-y","-i",concat_out,"-i",audio_path,
                            "-c:v","copy","-c:a","aac","-b:a","192k",
                            "-map","0:v:0","-map","1:a:0","-shortest"]
                           + fade_args + [video_final], capture_output=True)

            if not os.path.exists(video_final):
                raise Exception("FFmpeg no generó el video final al unir batches")

        size_mb = os.path.getsize(video_final) / (1024*1024)
        log(f"✅ Video listo — {size_mb:.1f} MB", 100)
        jobs[job_id].update({
            "estado":    "completado",
            "video_url": f"/api/descargar_render/{job_id}",
            "video_path": video_final,
            "size_mb":   round(size_mb,1),
            "duracion":  round(duracion_total,1),
            "escenas":   len(escenas_modal),
        })

    except Exception as e:
        import traceback; traceback.print_exc()
        log(f"❌ {str(e)}")
        jobs[job_id].update({"estado":"error","error":str(e)})
    finally:
        _sh.rmtree(tmp_dir, ignore_errors=True)


@app.route("/api/descargar_render/<job_id>")
def descargar_render(job_id):
    if job_id not in jobs: return jsonify({"error":"no encontrado"}),404
    path = jobs[job_id].get("video_path","")
    if not path or not os.path.exists(path): return jsonify({"error":"video no listo"}),404
    import re as _re
    proj = re.sub(r"[^\w\-]","_",jobs[job_id].get("mensaje","render"))[:30]
    return send_file(path, as_attachment=True, download_name=f"render_{job_id}.mp4")


@app.route("/api/proyectos/videos_final")
def proyecto_videos_final():
    proj_name = request.args.get("project","")
    if not proj_name: return jsonify({"videos":[]}), 200
    from pathlib import Path as _P
    vf_dir = _P(JOBS_FOLDER) / proj_name / "video_final"
    if not vf_dir.exists(): return jsonify({"videos":[]}), 200
    videos = sorted([f.name for f in vf_dir.glob("*.mp4")])
    return jsonify({"videos": videos})

@app.route("/api/proyectos/video_final")
def proyecto_video_final():
    proj_name = request.args.get("project","")
    fname     = request.args.get("file","")
    dl        = request.args.get("dl","0") == "1"
    if not proj_name or not fname: return jsonify({"error":"missing params"}),400
    from pathlib import Path as _P
    path = _P(JOBS_FOLDER) / proj_name / "video_final" / fname
    if not path.exists(): return jsonify({"error":"not found"}),404
    return send_file(str(path), as_attachment=dl, download_name=fname, mimetype="video/mp4")


@app.route("/api/guion/guardar", methods=["POST"])
def guion_guardar():
    data      = request.get_json() or {}
    proj_name = data.get("project_name", "").strip()
    texto     = data.get("texto", "").strip()
    prompts   = data.get("prompts", "").strip()
    if not proj_name or not texto:
        return jsonify({"error": "Faltan datos"}), 400
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    guion_dir = _P(JOBS_FOLDER) / proj_name / "guion"
    guion_dir.mkdir(parents=True, exist_ok=True)
    (guion_dir / "guion_fragmentado.txt").write_text(texto, encoding="utf-8")
    if prompts:
        (guion_dir / "prompts_imagen.txt").write_text(prompts, encoding="utf-8")
    return jsonify({"ok": True})

@app.route("/api/guion/cargar")
def guion_cargar():
    proj_name = request.args.get("project", "").strip()
    if not proj_name:
        return jsonify({"texto": "", "prompts": "", "existe": False})
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    guion_dir = _P(JOBS_FOLDER) / proj_name / "guion"
    path_g    = guion_dir / "guion_fragmentado.txt"
    path_p    = guion_dir / "prompts_imagen.txt"
    if path_g.exists():
        pts = path_p.read_text(encoding="utf-8") if path_p.exists() else ""
        return jsonify({"texto": path_g.read_text(encoding="utf-8"), "prompts": pts, "existe": True})
    return jsonify({"texto": "", "prompts": "", "existe": False})


@app.route("/api/audio/cargar")
def audio_cargar():
    proj_name = request.args.get("project", "").strip()
    if not proj_name:
        return jsonify({"existe": False, "archivos": []})
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    audio_dir = _P(JOBS_FOLDER) / proj_name / "audio"
    if not audio_dir.exists():
        return jsonify({"existe": False, "archivos": []})
    exts = {".mp3", ".wav", ".m4a", ".ogg", ".aac"}
    files = [f for f in audio_dir.iterdir() if f.is_file() and f.suffix.lower() in exts]
    if not files:
        return jsonify({"existe": False, "archivos": []})
    # Sort by modification time (newest first)
    files.sort(key=lambda f: f.stat().st_mtime, reverse=True)
    archivos = [f.name for f in files]
    return jsonify({"existe": True, "archivos": archivos, "principal": archivos[0]})

@app.route("/api/audio/archivo")
def audio_archivo():
    proj_name = request.args.get("project", "").strip()
    fname     = request.args.get("file", "").strip()
    if not proj_name or not fname:
        return jsonify({"error": "missing params"}), 400
    import re as _re
    from pathlib import Path as _P
    proj_name = _re.sub(r"[^\w\-]", "_", proj_name)
    path = _P(JOBS_FOLDER) / proj_name / "audio" / fname
    if not path.exists():
        return jsonify({"error": "not found"}), 404
    return send_file(str(path), mimetype="audio/mpeg",
                     download_name=fname, as_attachment=False)


